#include <batteries/bit_ops.hpp>

#include <gmock/gmock.h>
#include <gtest/gtest.h>

#include <type_traits>

namespace bit_ops_test {
using namespace batt::int_types;

using batt::get_bit;

inline i32 slow_next_bit(u64 bit_set, i32 index)
{
    for (++index; index < 64; ++index) {
        if (get_bit(bit_set, index)) {
            return index;
        }
    }
    return 64;
}

template <usize N>
inline i32 slow_next_bit(const std::array<u64, N>& bit_set, i32 index)
{
    for (++index; index < N * 64; ++index) {
        if (get_bit(bit_set[index / 64], index % 64)) {
            return index;
        }
    }

    return N * 64;
}

inline i32 slow_prev_bit(u64 bit_set, i32 index)
{
    for (--index; index >= 0; --index) {
        if (get_bit(bit_set, index)) {
            return index;
        }
    }
    return -1;
}

template <usize N>
inline i32 slow_prev_bit(const std::array<u64, N>& bit_set, i32 index)
{
    for (--index; index >= 0; --index) {
        if (get_bit(bit_set[index / 64], index % 64)) {
            return index;
        }
    }

    return -1;
}

inline i32 slow_first_bit(u64 bit_set)
{
    for (i32 index = 0; index < 64; ++index) {
        if (get_bit(bit_set, index)) {
            return index;
        }
    }
    return 64;
}

template <usize N>
inline i32 slow_first_bit(const std::array<u64, N>& bit_set)
{
    for (i32 index = 0; index < N * 64; ++index) {
        if (get_bit(bit_set[index / 64], index % 64)) {
            return index;
        }
    }

    return N * 64;
}

inline i32 slow_last_bit(u64 bit_set)
{
    for (i32 index = 64; index > 0;) {
        --index;
        if (get_bit(bit_set, index)) {
            return index;
        }
    }
    return -1;
}

template <usize N>
inline i32 slow_last_bit(const std::array<u64, N>& bit_set)
{
    for (i32 index = N * 64; index > 0;) {
        --index;
        if (get_bit(bit_set[index / 64], index % 64)) {
            return index;
        }
    }

    return -1;
}

inline i32 slow_bit_rank(u64 bit_set, i32 index)
{
    index = std::min<i32>(index, 63);
    i32 rank = -1;
    for (i32 j = 0; j <= index; ++j) {
        if (get_bit(bit_set, j)) {
            ++rank;
        }
    }
    return rank;
}

template <usize N>
inline i32 slow_bit_rank(const std::array<u64, N>& bit_set, i32 index)
{
    i32 rank = -1;
    for (i32 j = 0; j <=index; ++j) {
        if (get_bit(bit_set[j / 64], j % 64)) {
            ++rank;
        }
    }

    return rank;
}

inline i32 slow_bit_select(u64 bit_set, i32 rank)
{
    for (i32 index = 0; index < 64; ++index) {
        if (slow_bit_rank(bit_set, index) == rank) {
            return index;
        }
    }
    return 64;
}

template <usize N>
inline i32 slow_bit_select(const std::array<u64, N>& bit_set, i32 rank)
{
    for (i32 index = 0; index < N * 64; ++index) {
        if (slow_bit_rank(bit_set, index) == rank) {
            return index;
        }
    }
    return N * 64;
}

inline std::string bit_set_string(u64 bit_set)
{
    return std::bitset<64>(bit_set).to_string();
}

inline std::string bit_set_string(const std::array<u64, 2>& bit_set)
{
    return bit_set_string(bit_set[1]) + bit_set_string(bit_set[0]);
}

